var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"후유, 하마터면 목이 날아갈 뻔했구만.","JPN":"ふう、もう少しで首が飛ぶところだったぜ。","ENG":"Sheesh! Almost got my head chopped off.","TWN":"呼，我的脖子差點就要跟身體分家咧！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"좋아, 아가씨! 그대로 고개 숙이고 가만히 있으라구!","JPN":"いいぞ、お嬢ちゃん！　そのまま頭下げてじっとしてな！","ENG":"That's it, little lady! Keep your head down just like that!","TWN":"很好，小妹妹！就繼續低著頭吧！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"우으……. 아파파……","JPN":"うう……いたた……","ENG":"Oof... Oww...","TWN":"呃……好痛喔……"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"하필 거기서 총에 맞네. 상처 흉지면 안 되는데.","JPN":"よりによってあそこで銃に撃たれるなんて。傷跡残ったらどうするのよ。","ENG":"Just had to get hit right then and there. I hope it doesn't scar...","TWN":"偏偏打中這裡，拜託不要留疤。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"어휴, 끝도 없이 쏘네. 저래선 가까이 못 가겠어.","JPN":"もう、撃ちすぎ。あれじゃあ近づけないじゃない。","ENG":"Ugh, there’s no end to it. I can't get any closer to him.","TWN":"呼，真的是瘋狂掃射欸，根本沒辦法靠近他。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"그런데 이 냄새는……. 흐음……?","JPN":"でもこの匂いは……ふーん……？","ENG":"Huh? That smell... Hmm...?","TWN":"不過這個味道……嗯……？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"이봐, 당신들 민병대라고 했지?","JPN":"ねえ、あんたたち民兵隊なんでしょ？","ENG":"Hey, you guys are the Militia, right?","TWN":"喂，你們是民兵隊對吧？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"미안한데 우린 어중이떠중이 카운터들보다 훨씬 살벌한 침식체들이랑 부대끼고 사는 처지야.","JPN":"悪いけど、普段から私たちは役立たずのカウンターたちなんかじゃなくて、それよりずっと殺伐とした侵食体を相手してるの。","ENG":"I'm sorry to break it to you, but we live, breathe, and sleep next to C.O.s that are far more brutal than your average Counters.","TWN":"不好意思，我們可是對付過比半吊子制裁者更兇狠的侵蝕體。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"지금이라도 무기를 버리고 투항하는 게 어때. 러브 앤 피스, 좋잖아.","JPN":"今からでも武器を捨てて投降したらどう？　ラブ・アンド・ピース、結構じゃない。","ENG":"So do yourselves a favor and drop your weapons and surrender. Love and peace, am I right?","TWN":"你們立刻棄械投降吧，如何？愛與和平不是很好嗎？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"사양하지……! 러브 앤 피스는 그쪽이나 실컷 찾아!","JPN":"遠慮する……！　ラブ・アンド・ピースはそっちで探したらどうだ！","ENG":"I refuse...! You can go find your love and peace somewhere else!","TWN":"我拒絕……！你自己去愛與和平吧！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"역시 회장님 안목은 정확하군요. 평범해 보이는 용병 분들도 실력이 상당들 하시네요.","JPN":"やはり会長の目は正しいですね。平凡に見える傭兵の方々も相当な実力をお持ちです。","ENG":"As expected, our president has a good eye. Those ordinary-looking mercenaries seem to be quite skilled.","TWN":"會長的眼光果然沒錯，看似平凡的傭兵，能力也是相當不錯呢。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그러니 이제 저항은 포기하세요. 정면으로 부딪치는 건 그쪽 방식이 아닐 텐데요?","JPN":"ですから、もう抵抗は諦めなさい。正面からぶつかるのはそちらのやり方ではないでしょう？","ENG":"Stop resisting and put down your weapons. I know it's not your style to go in head first, no?","TWN":"放棄抵抗吧，正面衝突應該不是你們的行事風格吧？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"큭……! 닥쳐!","JPN":"くっ……！　黙れ！","ENG":"Kgh...! Shut up!","TWN":"咳……！閉嘴！"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"당신들이 저지르고 다니는 짓은 불법 행위에 지나지 않아요.","JPN":"あなたたちがしていることは不法行為に過ぎません。","ENG":"What you're doing is definitely against the law.","TWN":"你們的所作所為，無非就是非法行為。"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"설마 감정에만 호소하면 전부 용납된다고 생각하는 건가요?","JPN":"まさか感情に訴えれば全部許されるとでも思っているのですか？","ENG":"Or do you believe that if you appeal to emotion, everything will be forgiven?","TWN":"難道你們以為只要訴諸以情，就能夠將犯行合理化嗎？"},"stage":{"bg":"CORRIDOR_05","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};